module top_module(
    input clk,
    input load,
    input [7:0] data_in,
    output [7:0] data_out
);reg [7:0] reverse_shift_reg;

    always @(posedge clk) begin
        if (load) begin
            reverse_shift_reg <= data_in;
        end else begin
            reverse_shift_reg <= {reverse_shift_reg[6:0], reverse_shift_reg[7]};
        end
    end

    assign data_out = reverse_shift_reg;

endmodule
